var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"미나 선배…….","JPN":"ミナ先輩……","ENG":"Mina...","TWN":"米娜前輩……"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"역시 미나 선배는 날 포기하지 않았어…….","JPN":"やっぱりミナ先輩は、私のことを諦めてなかった……","ENG":"I knew it... Mina wouldn't give up on me.","TWN":"果然米娜前輩沒有放棄我……"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"스완, 당신이 말했죠?","JPN":"スワン、あなた言ってましたよね。","ENG":"Swan, you said it yourself, didn't you?","TWN":"史旺，你不是說了嗎？"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"이 극장이 보여주는 건, 틀림없이 과거의 한 장면이라고?","JPN":"この劇場が見せてくれるのは、間違いなく過去のある瞬間だって。","ENG":"That this theater shows scenes from the past.","TWN":"這個劇場展示的，肯定是過去的一個場景吧？"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그렇다면, 미나 선배가 절 구하러 오는 것도 분명 사실일 거예요! 그렇죠?","JPN":"じゃあ、ミナ先輩が私を助けに来てくれるのもきっと事実のはずです！　そうでしょう？","ENG":"If that's true, then Mina coming to save me... it has to be real too, right?","TWN":"那麼，米娜前輩來救我也一定是真的！對吧？"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"물론이에요. 노엘.","JPN":"もちろんです、ノエル。","ENG":"Of course, Noelle.","TWN":"當然是這樣。洛艾兒。"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 본 대로, 늑대는 당신을 찾고 있습니다.","JPN":"あなたが見た通り、オオカミはあなたを探しています。","ENG":"Just as you saw, the Wolf is searching for you.","TWN":"正如你所見，狼正在尋找你。"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 뿐만이 아니에요. 우리의 충직한 리트리버도 제 냄새를 맡은 모양이니까요.","JPN":"それだけではありません。忠犬レトリーバーも私の匂いを嗅ぎつけたようです。","ENG":"And it seems the loyal retriever has caught my scent as well.","TWN":"不僅如此，我們忠誠的獵犬似乎也聞到了我的氣味。"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"흥! 거 봐요!","JPN":"ふん！　ほら、だから言ったじゃないですか。","ENG":"Ha! See?","TWN":"哼！你看吧！"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"선배만 도착하면 당신도 끝이에요! 미나 선배는 무적이거든요!","JPN":"先輩が来たら、あなたもおしまいです！　ミナ先輩は無敵なんですから！","ENG":"Once Mina gets here, it's over for you! She's unstoppable!","TWN":"前輩一到，你也完蛋了！米娜前輩可是無敵的！"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"두고 봐요! 당신이 절 어떻게 괴롭혔는지, 선배한테 몽땅 일러 버릴 테니까!","JPN":"見てなさい。あなたがどうやって私を苛めたのか、先輩に全部チクってやりますから！","ENG":"Just wait! I'm going to tell her everything you did to me!","TWN":"等著瞧吧！我要把你怎麼欺負我的事情全都告訴前輩！"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후, 그것 참 기대되는군요.","JPN":"ふふ、それは楽しみですね。","ENG":"Haha, I look forward to it.","TWN":"呵呵，真是令人期待啊。"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 노엘. 이쯤 되면 한 가지 의문이 들지 않나요?","JPN":"ですが、ノエル。ここで1つ疑問が生じませんか？","ENG":"But, Noelle. By now, don't you find yourself wondering about one thing?","TWN":"但是洛艾兒。到這個時候，你不覺得有一個疑問嗎？"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"의문이라고요?","JPN":"え？　疑問？","ENG":"Wonder? About what?","TWN":"疑問？"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"클리파 차원에 유폐되어, 정보가 말소된 당신을… 늑대는 어떻게 기억하고 있을까요?","JPN":"クリファ次元に幽閉され情報が抹消されたあなたを……どうしてオオカミは覚えているのでしょう？","ENG":"You're trapped inside the Qlipha Dimension, and your information erased... And yet, how do you suppose the Wolf still remembers you?","TWN":"被囚禁在逆卡巴拉次元，資訊還被抹消的你……狼是怎麼記住的呢？"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"어, 어라……?","JPN":"あ、あれ……？","ENG":"H-huh...?","TWN":"啊，啊咧……？"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그, 그야! 미나 선배는 멋지고 강한 사람이니까요!","JPN":"そ、それはもちろん！　ミナ先輩は格好よくて強い人ですから！","ENG":"W-well, that's because Mina is amazing and strong!","TWN":"那，那是因為米娜前輩是又帥氣又強大的人啊！"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"멋지고 강하다? 그건 무슨 의미죠?","JPN":"格好よくて強い？　それはどういう意味ですか？","ENG":"Amazing and strong? What do you mean?","TWN":"帥氣又強大？那是什麼意思？"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"어어… 그러니까…….","JPN":"ええと……だから……","ENG":"I mean... Uh...","TWN":"呃呃……所以……"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"미나 선배는… 클리포트 게임으로부터 세상을 구한 영웅이라고요……!","JPN":"ミナ先輩は……クリフォトゲームから世界を救った英雄なんです……！","ENG":"She's the hero who saved the world from the Qliphoth Game.","TWN":"米娜前輩是……在逆卡巴拉遊戲中拯救世界的英雄……！"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그러니까 정보 말소 같은 건… 통하지 않는 게 틀림없어요! 흥……!","JPN":"だから情報抹消なんか……通じなくて当然です！　ふん……！","ENG":"So things like information erasure... there's no way that could work on her! Hmph!","TWN":"所以像資訊抹消之類的……肯定是行不通的！哼……！"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"글쎄요, 정보 말소는 하나의 자연 현상에 가깝습니다.","JPN":"どうでしょう、情報抹消は自然現象に近いものです。","ENG":"Well, information erasure is more like a natural phenomenon.","TWN":"嗯，資訊抹消更像是一種自然現象。"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"비가 내리면 모두가 공평하게 옷이 젖듯, 자연 현상은 인간의 강함과 약함을 가리지 않죠.","JPN":"落ちる雨があまねく全てを濡らすかのごとく、自然現象は強い人間にも弱い人間にも等しく適用されます。","ENG":"Just like rain soaks everyone equally, nature doesn't care if you're strong or weak.","TWN":"就像下雨時每個人的衣服都會被淋濕一樣，自然現象不會區分人的強弱。"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그, 그럼……?","JPN":"じゃ、じゃあ……？","ENG":"S-so what are you saying...?","TWN":"那，那……？"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"간단해요, 원인은 바로 당신이랍니다, 노엘 라이트.","JPN":"簡単です。原因はあなたなんですよ、ノエル・ライト。","ENG":"It's quite simple. You're the cause of all this, Noelle Wright.","TWN":"很簡單，原因就是你，洛艾兒·萊特。"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"네? 저요……?","JPN":"え？　私……？","ENG":"What? Me...?","TWN":"啊？你是在說我嗎……？"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 진심으로 바랐기 때문에, 늑대는 당신을 잊지 않고.","JPN":"あなたが心から願ったから、オオカミはあなたを忘れずにいる。","ENG":"Because you truly wished for it, the Wolf doesn't forget you.","TWN":"因為你真心期盼，狼不會忘記你。"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}}]`);export{e as default};